// ─── MONTHS CONFIG ────────────────────────────────────────────────────────
// month_index uses YYYYMM format (e.g. 202503 = March 2025, 202603 = March 2026)
// This ensures rows can be sorted correctly across any number of future years.
// To add future months, simply append more entries to this array.
const months = [
  { name: 'March 2025',     tab: 'March',          index: 202503 },
  { name: 'April 2025',     tab: 'April',          index: 202504 },
  { name: 'May 2025',       tab: 'May',            index: 202505 },
  { name: 'June 2025',      tab: 'June',           index: 202506 },
  { name: 'July 2025',      tab: 'July',           index: 202507 },
  { name: 'August 2025',    tab: 'August',         index: 202508 },
  { name: 'September 2025', tab: 'September',      index: 202509 },
  { name: 'October 2025',   tab: 'October',        index: 202510 },
  { name: 'November 2025',  tab: 'November',       index: 202511 },
  { name: 'December 2025',  tab: 'December',       index: 202512 },
  { name: 'January 2026',   tab: 'January 2026',   index: 202601 },
  { name: 'February 2026',  tab: 'February 2026',  index: 202602 },
  // ── Add new months below as the sheets grow ──────────────────────────────
  // { name: 'March 2026',     tab: 'March 2026',     index: 202603 },
  // { name: 'April 2026',     tab: 'April 2026',     index: 202604 },
];

return months.map(m => ({ json: m }));

// Transform Vince rows
const results = [];
for (const item of $input.all()) {
  const row = item.json;
  // Skip header/total rows
  const clientName = row['Client Name'] || row['client_name'] || '';
  if (!clientName || clientName.toLowerCase() === 'total' || clientName.toLowerCase() === 'client name') continue;

  const parseCurrency = (val) => {
    if (!val && val !== 0) return null;
    const cleaned = String(val).replace(/[$,\s]/g, '');
    const num = parseFloat(cleaned);
    return isNaN(num) ? null : num;
  };

  const parsePercent = (val) => {
    if (!val && val !== 0) return 20.00;
    const cleaned = String(val).replace(/%\s*/g, '');
    const num = parseFloat(cleaned);
    return isNaN(num) ? 20.00 : num;
  };

  results.push({
    json: {
      affiliate: 'Vince',
      client_name: String(clientName).trim(),
      month: row.__monthName || 'Unknown',
      month_index: row.__monthIndex || 0,
      billable_usd: parseCurrency(row['Client Billable ($)'] || row['client_billable']),
      referral_pct: parsePercent(row['Referral Fee (%)'] || row['referral_fee']),
      amount_owed: parseCurrency(row['Amount Owed ($)'] || row['amount_owed'])
    }
  });
}
return results;

