// Inject month metadata into each row before shipping to Sheets
// This runs BEFORE each sheet read; we relay the month info through the items
// NOTE: Because n8n Google Sheets node reads per-tab, we iterate months above
// and each sheet read returns rows; we need to tag them with month info.
// This code node merges the month context from upstream into sheet rows.

// The month info comes from the 'Month Config' node via $('Month Config').all()
// For each batch, we pass both datasets together.
const monthItems = $('Month Config').all();
const sheetItems = $input.all();

const mergedResults = [];
for (let i = 0; i < sheetItems.length; i++) {
  const sheetRow = sheetItems[i].json;
  // Find which month this item corresponds to
  // n8n loops the sheet read for each month iteration
  // We use pairedItem index to match
  const monthItem = monthItems[sheetItems[i].pairedItem?.item ?? 0]?.json;
  mergedResults.push({
    json: {
      ...sheetRow,
      __monthName: monthItem?.name,
      __monthIndex: monthItem?.index
    }
  });
}
return mergedResults;

